import { t as db } from "../../../../../chunks/db.js";
import "../../../../../chunks/oddsSync.service.js";
import { error } from "@sveltejs/kit";
//#region src/routes/sportsbook/match/[id]/+page.server.ts
var load = async ({ params, locals }) => {
	const [games] = await db.execute("SELECT id, sport FROM admin_games WHERE id = ? LIMIT 1", [params.id]);
	if (games.length === 0) throw error(404, "Fixture match not found");
	games[0];
	const [gameRaw] = await db.execute(`SELECT id, sport, league, home_team as homeTeam, away_team as awayTeam, start_time as startTime, status, home_score as homeScore, away_score as awayScore
     FROM admin_games 
     WHERE id = ? LIMIT 1`, [params.id]);
	const [markets] = await db.execute(`SELECT id, game_id as gameId, market_name as marketName, selection, odds, active 
     FROM admin_game_markets 
     WHERE game_id = ? AND active = 1`, [params.id]);
	return { game: {
		id: gameRaw[0].id,
		sport: gameRaw[0].sport,
		league: gameRaw[0].league,
		homeTeam: gameRaw[0].homeTeam,
		awayTeam: gameRaw[0].awayTeam,
		startTime: new Date(gameRaw[0].startTime),
		status: gameRaw[0].status,
		homeScore: gameRaw[0].homeScore !== null ? Number(gameRaw[0].homeScore) : null,
		awayScore: gameRaw[0].awayScore !== null ? Number(gameRaw[0].awayScore) : null,
		markets: markets.map((m) => ({
			id: m.id,
			gameId: m.gameId,
			marketName: m.marketName,
			selection: m.selection,
			odds: Number(m.odds),
			active: Boolean(m.active)
		}))
	} };
};
//#endregion
export { load };
